// This is NOT valid — if is a statement, not an expression
return (
  <div>
    {if (isLoggedIn) { <UserMenu /> }}  {/* SYNTAX ERROR */}
  </div>
);

// This IS valid — ternary is an expression
return (
  <div>
    {isLoggedIn ? <UserMenu /> : <LoginButton />}
  </div>
);

// Also valid — && is an expression
return (
  <div>
    {isLoggedIn && <UserMenu />}
  </div>
);

// Simple toggle between two elements
function AuthButton({ isLoggedIn, onLogin, onLogout }) {
  return (
    <button onClick={isLoggedIn ? onLogout : onLogin}>
      {isLoggedIn ? 'Log out' : 'Log in'}
    </button>
  );
}

// Swapping entire sections
function WelcomeBanner({ user }) {
  return (
    <section>
      {user
        ? (
          <div>
            <h2>Welcome back, {user.name}!</h2>
            <p>Last seen: {user.lastSeen}</p>
          </div>
        )
        : (
          <div>
            <h2>Welcome!</h2>
            <p>Please sign in to continue.</p>
          </div>
        )
      }
    </section>
  );
}

// These are equivalent:
{hasError ? <ErrorBanner /> : null}
{hasError && <ErrorBanner />}

// When to prefer one over the other:
// Prefer ternary when both branches are explicit and you want clarity:
{isLoading ? <Spinner /> : null}

// Prefer && when "nothing" is the default and you're adding an extra element:
{isAdmin && <AdminPanel />}

function Notification({ unreadCount, isPremium }) {
  return (
    <nav>
      <Logo />
      {/* Badge: show only when there are unread messages */}
      {unreadCount > 0 && (
        <span className="badge">{unreadCount}</span>
      )}
      {/* Premium indicator: show only for premium users */}
      {isPremium && <GoldStar />}
    </nav>
  );
}

// BUG — when items.length is 0, renders the text "0"
function ItemList({ items }) {
  return (
    <div>
      {items.length && <ul>{items.map(i => <li key={i}>{i}</li>)}</ul>}
    </div>
  );
}

// FIX 1 — compare to produce a boolean
function ItemListFixed({ items }) {
  return (
    <div>
      {items.length > 0 && <ul>{items.map(i => <li key={i}>{i}</li>)}</ul>}
    </div>
  );
}

// FIX 2 — coerce to boolean with !!
{!!items.length && <ul>...</ul>}

// FIX 3 — use ternary with null
{items.length ? <ul>...</ul> : null}

// Safe patterns that never produce "0":
{isLoading && <Spinner />}     // boolean — safe
{hasPermission && <Button />}  // boolean — safe
{count > 0 && <Badge />}       // comparison — safe

// ONE level — acceptable for simple cases
{isActive
  ? <ActiveBadge />
  : <InactiveBadge />
}

// TWO levels — already hard to follow
{isAdmin
  ? isSuperAdmin
    ? <SuperAdminPanel />
    : <AdminPanel />
  : <UserPanel />
}

// BETTER — extract to a function or use if/else
function RolePanel({ isAdmin, isSuperAdmin }) {
  if (isSuperAdmin) return <SuperAdminPanel />;
  if (isAdmin) return <AdminPanel />;
  return <UserPanel />;
}

// Or extract to a variable
function RolePanel({ isAdmin, isSuperAdmin }) {
  const panel = isSuperAdmin ? <SuperAdminPanel />
              : isAdmin      ? <AdminPanel />
              : <UserPanel />;
  return panel;
}
// Even this three-way ternary chain is borderline;
// the if chain version is clearer.

function Tab({ label, isActive, onClick }) {
  return (
    <button
      onClick={onClick}
      className={`tab ${isActive ? 'tab--active' : 'tab--inactive'}`}
      aria-selected={isActive}
    >
      {label}
    </button>
  );
}

// Conditional style object
function StatusDot({ online }) {
  return (
    <span
      style={{
        width: 8,
        height: 8,
        borderRadius: '50%',
        background: online ? '#22c55e' : '#9ca3af',
      }}
    />
  );
}

// Inline with template literal for multiple classes
function Card({ selected, disabled }) {
  return (
    <div
      className={[
        'card',
        selected ? 'card--selected' : '',
        disabled ? 'card--disabled' : '',
      ].filter(Boolean).join(' ')}
    />
  );
}

function SubmitButton({ isLoading, onClick }) {
  return (
    <button
      onClick={isLoading ? undefined : onClick}  // disable handler while loading
      disabled={isLoading}                        // disable the button itself
      aria-busy={isLoading}
    >
      {isLoading ? 'Saving…' : 'Save'}
    </button>
  );
}

// Spread different sets of props
function FlexibleInput({ isTextarea, ...props }) {
  const sharedProps = { className: 'input', ...props };
  return isTextarea
    ? <textarea {...sharedProps} />
    : <input {...sharedProps} />;
}

// Inline — good when branches are short
{isPremium ? <GoldBadge /> : <BasicBadge />}

// Multi-line — align ? and : at the same indent level
{isPremium
  ? <GoldBadge tier="premium" showGlow />
  : <BasicBadge showUpgradeHint />
}

// Parentheses for longer branches
{isPremium
  ? (
    <div className="badge gold">
      <Star /> Premium
    </div>
  )
  : (
    <div className="badge basic">
      Basic
    </div>
  )
}

function OrderStatus({ order }) {
  // Derive display state first — named variables explain intent
  const isDelivered = order.status === 'delivered' && !!order.deliveredAt;
  const isShipped   = order.status === 'shipped'   && !!order.trackingNumber;
  const canCancel   = ['pending', 'processing'].includes(order.status);
  const daysLate    = order.expectedDate
    ? Math.max(0, (new Date() - new Date(order.expectedDate)) / 86400000)
    : 0;

  return (
    <div>
      {/* Ternary uses the pre-computed variable, not the raw logic */}
      {isDelivered
        ? <DeliveredBanner deliveredAt={order.deliveredAt} />
        : <TrackingInfo order={order} />
      }
      {daysLate > 0 && <LateWarning days={daysLate} />}
      {canCancel && <CancelButton orderId={order.id} />}
    </div>
  );
}

import { render, screen } from '@testing-library/react';

test('shows logout button when logged in', () => {
  render(<AuthButton isLoggedIn={true} onLogout={jest.fn()} onLogin={jest.fn()} />);
  expect(screen.getByRole('button', { name: /log out/i })).toBeInTheDocument();
});

test('shows login button when not logged in', () => {
  render(<AuthButton isLoggedIn={false} onLogout={jest.fn()} onLogin={jest.fn()} />);
  expect(screen.getByRole('button', { name: /log in/i })).toBeInTheDocument();
});

test('badge not rendered when count is 0', () => {
  render(<Notification unreadCount={0} isPremium={false} />);
  expect(screen.queryByText('0')).not.toBeInTheDocument();
  expect(document.querySelector('.badge')).not.toBeInTheDocument();
});

test('badge shows count when positive', () => {
  render(<Notification unreadCount={5} isPremium={false} />);
  expect(screen.getByText('5')).toBeInTheDocument();
});

// Unmounts entirely — input value is lost on hide
function FilterPanel({ isOpen }) {
  return isOpen ? <Filters /> : null;
}

// Stays in DOM — CSS hides it; typed text preserved
function FilterPanel({ isOpen }) {
  return (
    <div className={isOpen ? '' : 'visually-hidden'}>
      <Filters />
    </div>
  );
}

/* visually-hidden in CSS */
.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
  white-space: nowrap;
}

import { useState } from 'react';

function ShowMore({ summary, children, defaultOpen = false }) {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  return (
    <div className="show-more">
      {isOpen ? children : <p className="preview">{summary}</p>}
      <button
        onClick={() => setIsOpen(prev => !prev)}
        aria-expanded={isOpen}
      >
        {isOpen ? 'Show less' : 'Read more'}
      </button>
    </div>
  );
}

// Usage
function ProductDescription({ product }) {
  return (
    <ShowMore summary={product.shortDescription}>
      <div dangerouslySetInnerHTML={{ __html: product.fullHtml }} />
    </ShowMore>
  );
}
